// n8n Code node — runs Mode: "Run Once for All Items"
// Reads CSV output directly from previous SSH nodes stdout

const COMPARE_COL = 'unit_cost_1';
const ID_COLS = ['product_id_1', 'product_name_1', 'mailing_method_name', 'day', 'min_quantity'];

// ── Read CSV content from SSH node stdout ──────────────────────────────────
const csv1 = $('qa2').first().json.stdout;
const csv2 = $('qa5').first().json.stdout;
const ENV1 = 'QA2';
const ENV2 = 'QA5';

// ── Parse CSV string → array of objects ───────────────────────────────────
function parseCSV(content) {
  const clean = content.replace(/^\uFEFF/, '').trim();
  const lines = clean.split('\n').filter(l => l.trim());
  const headers = lines[0].split(',').map(h => h.trim());
  return lines.slice(1).map(line => {
    const vals = line.split(',');
    return Object.fromEntries(headers.map((h, i) => [h, (vals[i] || '').trim()]));
  });
}

function rowKey(row) {
  return ID_COLS.map(c => row[c] || '').join('|');
}

const rows1 = parseCSV(csv1);
const rows2 = parseCSV(csv2);

const map1 = Object.fromEntries(rows1.map(r => [rowKey(r), r]));
const map2 = Object.fromEntries(rows2.map(r => [rowKey(r), r]));
const allKeys = [...new Set([...Object.keys(map1), ...Object.keys(map2)])];

const diffs = [];
const only1 = [];
const only2 = [];

for (const key of allKeys) {
  const r1 = map1[key];
  const r2 = map2[key];
  if (r1 && !r2) { only1.push(r1); continue; }
  if (r2 && !r1) { only2.push(r2); continue; }
  const v1 = r1[COMPARE_COL] || '';
  const v2 = r2[COMPARE_COL] || '';
  if (v1 !== v2) {
    const n1 = parseFloat(v1), n2 = parseFloat(v2);
    const delta = (!isNaN(n1) && !isNaN(n2))
      ? (() => { const d = Math.round((n2 - n1) * 10000) / 10000; return d > 0 ? `+${d}` : `${d}`; })()
      : 'N/A';
    diffs.push({
      product_id:     r1.product_id_1 || '',
      product_name:   r1.product_name_1 || '',
      mailing_method: r1.mailing_method_name || '',
      day:            r1.day || '',
      min_qty:        r1.min_quantity || '',
      val1: v1, val2: v2, delta
    });
  }
}

// ── Build HTML report ──────────────────────────────────────────────────────
const now = new Date().toLocaleString('ja-JP');
const diffCount = diffs.length;
const totalRows = allKeys.length;

const rowsHtml = diffs.length > 0
  ? diffs.map(d => {
      const dc = d.delta.startsWith('+') ? 'up' : 'down';
      return `<tr>
        <td>${d.product_id}</td>
        <td class="jp">${d.product_name}</td>
        <td class="jp">${d.mailing_method}</td>
        <td>${d.day}</td>
        <td>${d.min_qty}</td>
        <td class="mono e1">${d.val1}</td>
        <td class="mono e2">${d.val2}</td>
        <td class="mono ${dc}">${d.delta}</td>
      </tr>`;
    }).join('')
  : '<tr><td colspan="8" class="nodiff">No differences in unit_cost_1 — files are identical</td></tr>';

const missingHtml = [
  only1.length ? `<p class="warn">⚠ ${only1.length} rows only in ${ENV1}</p>` : '',
  only2.length ? `<p class="warn">⚠ ${only2.length} rows only in ${ENV2}</p>` : ''
].join('');

const statClass = diffCount > 0 ? 'red' : 'green';

const html = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8">
<title>unit_cost_1 diff · ${ENV1} vs ${ENV2}</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f5f5f5;color:#1a1a1a;font-size:14px}
.hdr{background:#1a1a1a;color:#fff;padding:1.5rem 2rem}
.hdr h1{font-size:1.15rem;font-weight:600;margin-bottom:.2rem}
.hdr p{font-size:.78rem;color:#888}
.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;padding:1.25rem 2rem}
.stat{background:#fff;border-radius:8px;padding:1rem 1.25rem;border:1px solid #e5e5e5}
.stat .num{font-size:1.75rem;font-weight:700}
.stat .lbl{font-size:.72rem;color:#888;margin-top:.2rem}
.red .num{color:#dc2626}.green .num{color:#16a34a}
.files{display:grid;grid-template-columns:1fr 1fr;gap:1rem;padding:0 2rem 1.25rem}
.file{background:#fff;border-radius:8px;padding:.875rem 1.25rem;border:1px solid #e5e5e5;font-size:.78rem}
.tag{display:inline-block;padding:1px 8px;border-radius:4px;font-size:.7rem;font-weight:700;margin-bottom:.3rem}
.e1 .tag{background:#dbeafe;color:#1d4ed8}.e2 .tag{background:#dcfce7;color:#166534}
.e1{color:#1d4ed8}.e2{color:#166534}
.path{color:#555;word-break:break-all}
.wrap{padding:0 2rem 2rem}
.warn{color:#b45309;background:#fef3c7;padding:.5rem 1rem;border-radius:6px;margin-bottom:.75rem;font-size:.8rem}
.search{margin-bottom:.875rem}
.search input{width:100%;padding:.5rem .875rem;border:1px solid #ddd;border-radius:6px;font-size:.875rem;outline:none}
.search input:focus{border-color:#666}
table{width:100%;border-collapse:collapse;background:#fff;border-radius:8px;overflow:hidden;border:1px solid #e5e5e5}
thead{background:#f9f9f9}
th{padding:.6rem .875rem;text-align:left;font-weight:600;font-size:.72rem;color:#555;border-bottom:1px solid #e5e5e5;white-space:nowrap}
td{padding:.5rem .875rem;border-bottom:1px solid #f0f0f0;vertical-align:middle}
tr:last-child td{border-bottom:none}
tr:hover td{background:#fafafa}
.mono{font-family:monospace;font-size:.8rem}
.up{color:#dc2626;font-weight:600}.down{color:#16a34a;font-weight:600}
.jp{font-size:.78rem}
.nodiff{text-align:center;padding:2rem;color:#16a34a;font-weight:500}
.hidden{display:none}
</style></head><body>
<div class="hdr">
  <h1>unit_cost_1 diff &nbsp;·&nbsp;
    <span style="color:#60a5fa">${ENV1}</span> vs
    <span style="color:#4ade80">${ENV2}</span>
  </h1>
  <p>Generated ${now}</p>
</div>
<div class="stats">
  <div class="stat"><div class="num">${totalRows}</div><div class="lbl">Total rows</div></div>
  <div class="stat ${statClass}"><div class="num">${diffCount}</div><div class="lbl">Rows with diff</div></div>
  <div class="stat"><div class="num">${only1.length}</div><div class="lbl">Only in ${ENV1}</div></div>
  <div class="stat"><div class="num">${only2.length}</div><div class="lbl">Only in ${ENV2}</div></div>
</div>
<div class="files">
  <div class="file e1"><span class="tag">${ENV1}</span><div class="path">debug_estimation_price_cost_qa2.csv</div></div>
  <div class="file e2"><span class="tag">${ENV2}</span><div class="path">debug_estimation_price_cost_qa5.csv</div></div>
</div>
<div class="wrap">
  ${missingHtml}
  <div class="search"><input type="text" id="s" placeholder="Filter by product, method, value..." oninput="filter()"></div>
  <table><thead><tr>
    <th>Product ID</th><th>Product name</th><th>Mailing method</th><th>Day</th><th>Min qty</th>
    <th><span style="background:#dbeafe;color:#1d4ed8;padding:1px 6px;border-radius:4px;font-size:.7rem">${ENV1}</span> unit_cost_1</th>
    <th><span style="background:#dcfce7;color:#166534;padding:1px 6px;border-radius:4px;font-size:.7rem">${ENV2}</span> unit_cost_1</th>
    <th>Delta</th>
  </tr></thead>
  <tbody id="tb">${rowsHtml}</tbody></table>
</div>
<script>
function filter(){const q=document.getElementById('s').value.toLowerCase();document.querySelectorAll('#tb tr').forEach(r=>r.classList.toggle('hidden',!r.textContent.toLowerCase().includes(q)));}
</script>
</body></html>`;

return [{ json: { html, diff_count: diffCount, total_rows: totalRows } }];
